import React, {useEffect, useRef} from "react";
import type { ICircularProgressProps } from "@lmb-it/kitsconcerto-types";
import Svg, { Circle, G } from "react-native-svg";
import { View, Animated, Easing } from "react-native";
import {Box} from "../../_compat";

const CircularProgress = ({
                              size = 100,
                              strokeWidth = 8,
                              value,
                              color = "blue",
                              trackColor = "lightgray",
                              loading = false,
                              children,
                          }: ICircularProgressProps) => {

    const radius = (size - strokeWidth) / 2;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (value / 100) * circumference;

    const rotateAnim = useRef(new Animated.Value(0)).current;

    useEffect(() => {
        if (loading) {
            rotateAnim.setValue(0);
            Animated.loop(
                Animated.timing(rotateAnim, {
                    toValue: 1,
                    duration: 1200,
                    easing: Easing.linear,
                    useNativeDriver: true,
                })
            ).start();
        } else {
            rotateAnim.stopAnimation();
        }
    }, [loading]);

    const rotation = rotateAnim.interpolate({
        inputRange: [0, 1],
        outputRange: ["0deg", "360deg"],
    });

    return (
        <View
            style={{
                width: size,
                height: size,
                justifyContent: "center",
                alignItems: "center",
            }}
        >
            {/*
        WORKING rotation:
        1. Shift SVG to center (translate)
        2. Rotate the whole SVG
        3. Shift it back
      */}

            <Svg width={size} height={size}>
                {/* Track */}
                <Circle
                    cx={size / 2}
                    cy={size / 2}
                    r={radius}
                    stroke={trackColor}
                    strokeWidth={strokeWidth}
                    fill="none"
                />

                {/* Determinate mode */}
                {!loading && <Circle
                    cx={size / 2}
                    cy={size / 2}
                    r={radius}
                    stroke={color}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={offset}
                    strokeLinecap="round"
                    fill="none"
                />}
            </Svg>

            {loading && <Animated.View
                style={{
                    position: "absolute",
                    transform: [
                        {rotate: rotation},
                    ],
                }}
            >
                <Svg width={size} height={size}>
                    <Circle
                        cx={size / 2}
                        cy={size / 2}
                        r={radius}
                        stroke={color}
                        strokeWidth={strokeWidth}
                        strokeDasharray={circumference}
                        strokeDashoffset={offset}
                        strokeLinecap="round"
                        fill="none"
                    />
                </Svg>
            </Animated.View>}


            {/* Center Content */}
            {children && (
                <Box
                    style={{
                        position: "absolute",
                        justifyContent: "center",
                        alignItems: "center",
                    }}
                >
                    {children}
                </Box>
            )}
        </View>
    );
};

export default CircularProgress;
